mapper.select:
select
ei.id as eventId, ei.event_name as eventName, eti.`type_name` as typeName, ei.event_type_id as typeId,ci.people_pic as peoplePic,
ci.complain_name,ci.complain_type,ci.complain_unit,ci.complain_people,dm2.`name` as memberName,
ei.expire_date as expireDate,ei.event_status as eventStatus,ei.address,ei.lng,ei.lat,ei.happen_time as happenTime,
ei.is_need_intervene as isNeedIntervene, di.`name` as departName, dm.head_icon as headIcon,dm.phone_number as phoneNumber,
ei.event_level as eventLevel, ei.event_publisher as publisher, ei.create_time as createTime
FROM event_info ei
LEFT JOIN event_type_info eti on eti.id = ei.event_type_id
LEFT JOIN event_depart_member edm ON ei.id = edm.event_id
LEFT JOIN department_member dm ON edm.depart_member_id = dm.id
LEFT JOIN department_member dm2 ON ei.report_member_id = dm2.id
LEFT JOIN department_info di ON dm.department_id = di.id
LEFT JOIN complain_event_info cei ON cei.event_id = ei.id
LEFT JOIN complain_info ci ON ci.id = cei.complain_id
where ei.report_status=#{reportStatus}

    and ei.event_type_id = #{eventTypeId}


    and ei.event_level = #{eventLevel}


    and ei.event_name like CONCAT('%',#{eventName},'%')


    AND dm.department_id = #{departId}


    and ei.event_status in

        #{item}




        and ei.create_time >= #{startTime}


        and ei.create_time <= #{endTime}


        and ei.create_time between #{startTime} and #{endTime}


GROUP BY eventId
order by ei.create_time desc

SELECT
ei.id as eventId, ei.event_name as eventName, ei.event_type_id as eventTypeId,
eti.type_name as typeName, ei.event_status as eventStatus,ei.address,ei.lng,ei.lat,
ei.event_level as eventLevel, ei.event_content as eventContent,ei.happen_time as happenTime,
ei.create_time as createTime,ei.report_member_id as reportMemberId,edm.`name` as memberName,edm.phone_number phone,
edm.head_icon as headIcon
FROM event_info ei
LEFT JOIN department_member edm ON ei.report_member_id = edm.id
LEFT JOIN event_type_info eti ON ei.event_type_id = eti.id
WHERE ei.report_status = 1

    AND edm.department_id = #{departId}


    and ei.event_status=#{eventStatus}


    and edm.title=#{title}



        and ei.create_time between #{startTime} and #{endTime}


        and ei.create_time >= #{startTime}


        and ei.create_time <= #{endTime}


order by ei.create_time desc

select
ei.id as eventId, ei.event_name as eventName, eti.`type_name` as typeName, ei.event_type_id as typeId,
ei.expire_date as expireDate,ei.event_status as eventStatus,ei.address,ei.lng,ei.lat,ei.happen_time as
happenTime, dm.head_icon as headIcon,
ei.event_level as eventLevel, ei.event_publisher as publisher, ei.create_time as createTime
FROM event_info ei
LEFT JOIN event_type_info eti on eti.id = ei.event_type_id
LEFT JOIN event_punish edm ON ei.id = edm.event_id
LEFT JOIN department_info di ON di.id = edm.exeute_depart_id
LEFT JOIN department_member dm ON di.leader = dm.id
where ei.report_status=#{reportStatus}

    and ei.event_type_id = #{eventTypeId}


    and ei.event_level = #{eventLevel}


    and ei.event_name like CONCAT('%',#{eventName},'%')


    AND edm.exeute_depart_id = #{departId}


    and ei.event_status = #{eventStatus}



        and ei.create_time >= #{startTime}


        and ei.create_time <= #{endTime}


        and ei.create_time between #{startTime} and #{endTime}


order by ei.create_time desc
